  Save, Play, User, Cog, GitBranch, Flag, Plus, 
  Menu, Search, Box, Ruler, Smartphone, X, Landmark, Users as UsersIcon, ChevronDown
} from 'lucide-react';

const GRID_SIZE = 20;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, groups } = useBPM();
  const [processName, setProcessName] = useState('Enterprise Workflow v2');

  // -- UI States --
  const [isPaletteOpen, setIsPaletteOpen] = useState(window.innerWidth > 1024);
  const [isPropertiesOpen, setIsPropertiesOpen] = useState(false);
  const [showGrid, setShowGrid] = useState(true);
  const [isMobilePreview, setIsMobilePreview] = useState(window.innerWidth < 768);

  // -- Editor Core State --
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [lanes, setLanes] = useState<Swimlane[]>([
    { id: 'lane-1', name: 'Operational Layer', height: 250 },
    { id: 'lane-2', name: 'Management Control', height: 250 }
  ]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const addNode = (type: ProcessStep['type']) => {
    const world = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: `New ${type.replace('-', ' ')}`,
      type,
      description: '',
      position: { x: snapToGrid(world.x), y: snapToGrid(world.y) },
      nextStepIds: []
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
    setIsPropertiesOpen(true);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) {
      dragTarget.current = 'link';
      activeId.current = handleEl.getAttribute('data-handle-id');
    } else if (nodeEl) {
      dragTarget.current = 'node';
      activeId.current = nodeEl.getAttribute('data-node-id');
      setSelectedId(activeId.current);
      setIsPropertiesOpen(true);
    } else {
      dragTarget.current = 'viewport';
      if (!isPropertiesOpen) setSelectedId(null);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = (e.clientX - dragStart.current.x) / viewport.zoom;
    const dy = (e.clientY - dragStart.current.y) / viewport.zoom;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { 
        ...s, 
        position: { x: (s.position?.x || 0) + dx, y: (s.position?.y || 0) + dy } 
      } : s));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'link' && activeId.current) {
      const sNode = steps.find(s => s.id === activeId.current);
      if (sNode) {
        const world = screenToWorld(e.clientX, e.clientY);
        ghostLink.current = { x1: (sNode.position?.x||0)+180, y1: (sNode.position?.y||0)+40, x2: world.x, y2: world.y };
        setViewport(v => ({...v}));
      }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      if (tId && tId !== activeId.current) {
        setLinks(prev => [...prev, { id: `link-${Date.now()}`, sourceId: activeId.current!, targetId: tId }]);
      }
    }

    if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? {
         ...s,
         position: { x: snapToGrid(s.position?.x||0), y: snapToGrid(s.position?.y||0) }
       } : s));
    }

    isDragging.current = false;
    ghostLink.current = null;
    setViewport(v => ({...v}));
  };

  const selectedStep = steps.find(s => s.id === selectedId);

  return (
    <div className={`h-[calc(100vh-140px)] flex flex-col md:flex-row bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden relative shadow-2xl transition-all ${isMobilePreview ? 'max-w-[420px] mx-auto ring-8 ring-slate-800' : 'w-full'}`}>

      {/* Dynamic Header */}
      <div className="bg-white border-b border-slate-200 p-3 flex justify-between items-center z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsPaletteOpen(!isPaletteOpen)} className="p-2 bg-slate-50 border rounded-lg hover:bg-slate-100"><Menu size={18}/></button>
          <input className="w-48 px-3 py-1.5 bg-slate-50 border rounded-lg text-xs font-bold" value={processName} onChange={e => setProcessName(e.target.value)}/>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={() => setShowGrid(!showGrid)} className={`p-2 ${showGrid ? 'text-brand-600' : 'text-slate-400'}`}><Ruler size={18}/></button>
           <button onClick={() => setIsMobilePreview(!isMobilePreview)} className={`p-2 ${isMobilePreview ? 'text-brand-600' : 'text-slate-400'}`}><Smartphone size={18}/></button>
           <div className="h-6 w-px bg-slate-200 mx-2"></div>
           <button onClick={() => deployProcess({ name: processName, description: 'Enterprise Workflow', steps, links, lanes, deployedBy: 'Principal Admin' })} className="bg-brand-600 text-white px-4 py-1.5 rounded-lg font-bold text-xs shadow-lg hover:bg-brand-700 flex items-center gap-2">
             <Save size={16}/> Deploy
           </button>
        </div>
      </div>

      {/* Palette */}
      <aside className={`absolute inset-y-0 left-0 w-72 bg-white/95 backdrop-blur-md border-r border-slate-200 z-40 transition-transform duration-300 transform md:relative md:translate-x-0 ${isPaletteOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}`}>
        <div className="p-4 border-b flex justify-between items-center">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Modeler Palette</span>
          <button onClick={() => setIsPaletteOpen(false)} className="md:hidden"><X size={16}/></button>
        </div>
        <div className="p-4 space-y-6 overflow-y-auto h-full scrollbar-hide pb-20">
           <section className="space-y-2">
             <h4 className="text-[9px] font-bold text-slate-400 uppercase">Flow Components</h4>
             <div className="grid grid-cols-2 gap-2">
                <PaletteItem icon={Play} label="Start" color="text-green-500" onClick={() => addNode('start')} />
                <PaletteItem icon={Flag} label="End" color="text-slate-800" onClick={() => addNode('end')} />
                <PaletteItem icon={User} label="Human" color="text-blue-500" onClick={() => addNode('user-task')} />
                <PaletteItem icon={Cog} label="System" color="text-purple-500" onClick={() => addNode('service-task')} />
                <PaletteItem icon={GitBranch} label="XOR Gate" color="text-amber-500" onClick={() => addNode('decision')} />
                <PaletteItem icon={Box} label="Subprocess" color="text-indigo-500" onClick={() => addNode('sub-process')} />
             </div>
           </section>
        </div>
      </aside>

      {/* Canvas */}
      <div className="flex-1 relative overflow-hidden bg-slate-50 touch-none select-none">
        <div ref={canvasRef} className="absolute inset-0 cursor-crosshair" onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}
          style={{ backgroundImage: showGrid ? 'radial-gradient(#cbd5e1 1.5px, transparent 1.5px)' : 'none', backgroundSize: `${20*viewport.zoom}px ${20*viewport.zoom}px`, backgroundPosition: `${viewport.x}px ${viewport.y}px` }}>
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
            <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
              <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#94a3b8"/></marker></defs>
              {links.map(l => {
                const s = steps.find(n => n.id === l.sourceId);
                const t = steps.find(n => n.id === l.targetId);
                if (!s || !t) return null;
                const x1=(s.position?.x||0)+180; const y1=(s.position?.y||0)+40;
                const x2=(t.position?.x||0); const y2=(t.position?.y||0)+40;
                return <path key={l.id} d={`M ${x1} ${y1} C ${x1+60} ${y1}, ${x2-60} ${y2}, ${x2} ${y2}`} stroke="#94a3b8" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>
              })}
              {ghostLink.current && <line x1={ghostLink.current.x1} y1={ghostLink.current.y1} x2={ghostLink.current.x2} y2={ghostLink.current.y2} stroke="#0ea5e9" strokeWidth="2" strokeDasharray="4,4"/>}
            </svg>

            {steps.map(step => (
              <div key={step.id} data-node-id={step.id}
                className={`absolute w-[180px] h-[80px] bg-white rounded-xl border-2 shadow-sm p-3 flex flex-col transition-all active:scale-95 ${selectedId === step.id ? 'border-brand-500 shadow-xl z-30 scale-105' : 'border-slate-200'}`}
                style={{ left: step.position?.x, top: step.position?.y }}>
                <div className="flex items-center justify-between opacity-50 mb-1">
                  <span className="text-[8px] font-black uppercase text-slate-400">{step.type}</span>
                  <div data-handle-id={step.id} className="w-5 h-5 bg-slate-100 border rounded-full flex items-center justify-center cursor-crosshair hover:bg-brand-500 hover:text-white transition-colors"><Plus size={10}/></div>
                </div>
                <div className="text-xs font-bold text-slate-800 truncate">{step.name}</div>
                <div className="mt-auto flex justify-between items-center text-[7px] font-bold text-slate-400">
                   <span className="bg-slate-50 px-1 rounded uppercase flex items-center gap-1">
                      {step.role ? <Shield size={8}/> : step.groupId ? <Landmark size={8}/> : null}
                      {step.role || step.groupId || 'Unassigned'}
                   </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Property Panel */}
      <aside className={`fixed inset-x-0 bottom-0 bg-white shadow-2xl z-[60] border-t transition-transform duration-500 md:relative md:inset-y-0 md:border-t-0 md:border-l md:w-96 md:translate-y-0 ${selectedId && isPropertiesOpen ? 'translate-y-0' : 'translate-y-full'}`}>
         <div className="p-4 border-b flex items-center justify-between bg-slate-50/50">
            <h3 className="font-black text-slate-800 text-xs uppercase tracking-widest">Enterprise Routing</h3>
            <button onClick={() => setIsPropertiesOpen(false)} className="p-2 text-slate-400 hover:bg-slate-100 rounded-lg"><ChevronDown size={18}/></button>
         </div>
         {selectedStep && (
           <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh] md:max-h-full scrollbar-hide">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Activity Label</label>
                <input className="w-full p-3 bg-slate-50 border rounded-xl text-sm font-bold focus:ring-2 focus:ring-brand-500" value={selectedStep.name} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, name: e.target.value} : s))}/>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Target Role</label>
                  <select 
                    className="w-full p-3 bg-slate-50 border rounded-xl text-sm appearance-none"
                    value={selectedStep.role || ''}
                    onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, role: e.target.value, groupId: undefined} : s))}
                  >
                    <option value="">None (Generic)</option>
                    {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">OR Target Group</label>
                  <select 
                    className="w-full p-3 bg-slate-50 border rounded-xl text-sm appearance-none"
                    value={selectedStep.groupId || ''}
                    onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, groupId: e.target.value, role: undefined} : s))}
                  >
                    <option value="">None (Generic)</option>
                    {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                  </select>
                </div>
              </div>

              <div className="pt-4 border-t flex gap-3">
                 <button onClick={() => { setSteps(prev => prev.filter(s => s.id !== selectedId)); setLinks(prev => prev.filter(l => l.sourceId !== selectedId && l.targetId !== selectedId)); setSelectedId(null); }} className="flex-1 py-3 bg-red-50 text-red-700 rounded-xl font-bold text-xs uppercase">Delete</button>
                 <button className="flex-1 py-3 bg-brand-600 text-white rounded-xl font-bold text-xs uppercase" onClick={() => setIsPropertiesOpen(false)}>Commit</button>
              </div>
           </div>
         )}
      </aside>
    </div>
  );
};

const PaletteItem = ({ icon: Icon, label, color, onClick }: any) => (
  <button onClick={onClick} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 transition-all hover:shadow-md">
    <Icon size={20} className={color}/>
    <span className="text-[10px] font-bold text-slate-600">{label}</span>
  </button>
);

const Shield = ({ size }: { size: number }) => <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>;

export enum TaskStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export enum Permission {
  PROCESS_VIEW = 'process:view',
  PROCESS_DEPLOY = 'process:deploy',
  PROCESS_START = 'process:start',
  TASK_COMPLETE = 'task:complete',
  TASK_OVERRIDE = 'task:override',
  ADMIN_ACCESS = 'admin:access',
  USER_MANAGE = 'user:manage',
  SYSTEM_CONFIG = 'system:config'
}

export interface UserRole {
  id: string;
  name: string;
  permissions: Permission[];
}

export interface UserGroup {
  id: string;
  name: string;
  parentGroupId?: string;
  description: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar?: string;
  roleIds: string[];
  groupIds: string[];
  skills: string[];
  location: string;
  status: 'Active' | 'On Leave' | 'Terminated';
  delegateToId?: string; 
  lastLogin?: string;
  domainId: string;
}

export interface Delegation {
  id: string;
  fromUserId: string;
  toUserId: string;
  startDate: string;
  endDate: string;
  isActive: boolean;
  scope: 'All' | 'Critical Only';
}

export interface Comment {
  id: string;
  userId: string;
  userName: string;
  text: string;
  timestamp: string;
}

export interface Attachment {
  id: string;
  name: string;
  type: string;
  size: number;
  uploadDate: string;
}

export interface Task {
  id: string;
  title: string;
  processName: string;
  processInstanceId: string;
  assignee: string; 
  candidateRoles: string[]; 
  candidateGroups: string[];
  requiredSkills: string[];
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string;
  data?: any;
  comments: Comment[];
  attachments: Attachment[];
}

export interface ProcessStep {
  id: string;
  name: string;
  type: 'start' | 'user-task' | 'service-task' | 'decision' | 'parallel-gateway' | 'end' | 'note' | 'sub-process' | 'boundary-event';
  description: string;
  role?: string; 
  groupId?: string; 
  requiredSkills?: string[];
  laneId?: string;
  slaDays?: number;
  nextStepIds?: string[];
  position?: { x: number; y: number };
  isCollapsed?: boolean;
}

export interface ProcessLink {
  id: string;
  sourceId: string;
  targetId: string;
  label?: string;
  condition?: string;
}

export interface Swimlane {
  id: string;
  name: string;
  height: number;
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
  links?: ProcessLink[];
  lanes?: Swimlane[];
  createdAt: string;
  deployedBy: string;
  version: number;
  isActive: boolean;
  complianceLevel: 'Standard' | 'Strict' | 'Critical';
  history?: { timestamp: string; author: string; message: string }[];
  domainId: string;
}

export interface AuditLog {
  id: string;
  timestamp: string;
  userId: string;
  action: string;
  entityType: 'Process' | 'Task' | 'Instance' | 'System' | 'User';
  entityId: string;
  details: string;
  severity: 'Info' | 'Warning' | 'Alert';
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated' | 'Suspended';
  activeStepIds: string[];
  startDate: string;
  endDate?: string;
  dueDate?: string;
  variables: Record<string, any>;
  priority: TaskPriority;
  history: TaskHistory[];
  comments: Comment[];
  complianceVerified: boolean;
  domainId: string; 
}

export type ViewState = 
  | 'dashboard' 
  | 'inbox' 
  | 'explorer' 
  | 'processes' 
  | 'designer' 
  | 'analytics' 
  | 'governance' 
  | 'settings' 
  | 'identity' 
  | 'instance-viewer';

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback, useRef } from 'react';
import { 
  ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, 
  TaskHistory, ProcessStep, ViewState, AuditLog, Comment,
  User, UserRole, UserGroup, Permission, Delegation 
} from '../types';
import { dbService } from '../services/dbService';

interface NavigationState {
  view: ViewState;
  selectedId?: string;
  filter?: string;
  mode?: 'view' | 'edit';
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  auditLogs: AuditLog[];
  users: User[];
  roles: UserRole[];
  groups: UserGroup[];
  delegations: Delegation[];
  currentUser: User | null;
  loading: boolean;
  error: string | null;
  nav: NavigationState;

  navigateTo: (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => void;
  viewingInstanceId: string | null;
  openInstanceViewer: (instanceId: string) => void;
  closeInstanceViewer: () => void;

  setCurrentUser: (user: User) => void;
  hasPermission: (perm: Permission) => boolean;

  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt' | 'version' | 'isActive' | 'domainId'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;

  claimTask: (taskId: string) => Promise<void>;
  releaseTask: (taskId: string) => Promise<void>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;
  addTaskComment: (taskId: string, text: string) => Promise<void>;

  updateUser: (user: User) => Promise<void>;
  addDelegation: (del: Omit<Delegation, 'id'>) => Promise<void>;
  revokeDelegation: (id: string) => Promise<void>;

  adminOverrideStep: (instanceId: string, targetStepId: string) => Promise<void>;
  updateInstanceVariables: (instanceId: string, variables: Record<string, any>) => Promise<void>;
  toggleInstanceSuspension: (instanceId: string) => Promise<void>;
  addInstanceComment: (instanceId: string, text: string) => Promise<void>;

  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [roles, setRoles] = useState<UserRole[]>([]);
  const [groups, setGroups] = useState<UserGroup[]>([]);
  const [delegations, setDelegations] = useState<Delegation[]>([]);
  const [currentUser, setLocalCurrentUser] = useState<User | null>(null);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [nav, setNav] = useState<NavigationState>({ view: 'dashboard' });
  const [viewingInstanceId, setViewingInstanceId] = useState<string | null>(null);

  const stateRef = useRef({ processes, instances, tasks, auditLogs, users, roles, groups, currentUser, delegations });

  useEffect(() => {
    stateRef.current = { processes, instances, tasks, auditLogs, users, roles, groups, currentUser, delegations };
  }, [processes, instances, tasks, auditLogs, users, roles, groups, currentUser, delegations]);

  const logAudit = async (action: string, entityType: AuditLog['entityType'], entityId: string, details: string, severity: AuditLog['severity'] = 'Info') => {
    const log: AuditLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      timestamp: new Date().toISOString(),
      userId: currentUser?.name || 'system',
      action,
      entityType,
      entityId,
      details,
      severity
    };
    await dbService.add('auditLogs', log);
    setAuditLogs(prev => [log, ...prev]);
  };

  const hasPermission = (perm: Permission): boolean => {
    if (!currentUser) return false;
    const userRoles = roles.filter(r => currentUser.roleIds.includes(r.id));
    return userRoles.some(r => r.permissions.includes(perm));
  };

  const navigateTo = (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => {
    setNav({ view, selectedId: id, filter, mode });
  };

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [p, i, t, al, u, r, g, d] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks'),
        dbService.getAll<AuditLog>('auditLogs'),
        dbService.getAll<User>('users'),
        dbService.getAll<UserRole>('roles'),
        dbService.getAll<UserGroup>('groups'),
        dbService.getAll<Delegation>('delegations')
      ]);
      setProcesses(p);
      setInstances(i);
      setTasks(t);
      setAuditLogs(al || []);
      setUsers(u);
      setRoles(r);
      setGroups(g);
      setDelegations(d || []);

      if (u.length > 0 && !stateRef.current.currentUser) {
        setLocalCurrentUser(u.find(user => user.roleIds.includes('admin')) || u[0]);
      }
    } catch (e: any) {
      setError(e.message || "DB Error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt' | 'version' | 'isActive' | 'domainId'>) => {
    if (!hasPermission(Permission.PROCESS_DEPLOY)) throw new Error("Unauthorized to deploy processes");

    const existing = processes.find(p => p.name === processData.name);
    const newVersion = existing ? existing.version + 1 : 1;

    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
      version: newVersion,
      isActive: true,
      complianceLevel: processData.complianceLevel || 'Standard',
      domainId: currentUser?.domainId || 'default'
    };

    await dbService.add('processes', newProcess);
    await logAudit('DEPLOY', 'Process', newProcess.id, `Deployed version ${newVersion} of ${newProcess.name}`);

    setProcesses(prev => [newProcess, ...prev.map(p => p.name === processData.name ? { ...p, isActive: false } : p)]);
    navigateTo('processes');
  };

  const advanceWorkflow = async (instanceId: string, completedStepId: string, action: string) => {
    const { processes, instances } = stateRef.current;
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const definition = processes.find(p => p.id === instance.definitionId);
    if (!definition) return;

    const outgoingLinks = definition.links?.filter(l => l.sourceId === completedStepId) || [];
    let nextStepIds: string[] = [];

    if (outgoingLinks.length > 0) {
      nextStepIds = outgoingLinks.map(l => l.targetId);
    } else {
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);
    let updatedInstance = { ...instance, activeStepIds: newActiveStepIds };

    if (nextStepIds.length === 0 || nextStepIds.some(id => definition.steps.find(s => s.id === id)?.type === 'end')) {
      updatedInstance.status = 'Completed';
      updatedInstance.endDate = new Date().toISOString();
      updatedInstance.activeStepIds = [];
      await logAudit('FINISH', 'Instance', instance.id, `Process instance completed: ${definition.name}`);
    }

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));

    for (const stepId of nextStepIds) {
      const step = definition.steps.find(s => s.id === stepId);
      if (step) await executeStepLogic(updatedInstance, definition, step);
    }
  };

  const executeStepLogic = async (instance: ProcessInstance, definition: ProcessDefinition, step: ProcessStep) => {
    if (step.type === 'service-task') {
      setTimeout(async () => {
        const hist: TaskHistory = {
          id: `h-${Date.now()}`,
          stepName: step.name,
          action: 'Auto-Complete',
          performer: 'System Integration',
          timestamp: new Date().toISOString()
        };
        const fresh = await dbService.getAll<ProcessInstance>('instances');
        const inst = fresh.find(i => i.id === instance.id)!;
        const updated = { ...inst, history: [...inst.history, hist] };
        await dbService.add('instances', updated);
        await advanceWorkflow(instance.id, step.id, 'system_complete');
      }, 1000);
    } else if (step.type === 'user-task') {
      const newTask: Task = {
        id: `T-${Date.now()}`,
        title: step.name,
        processName: definition.name,
        processInstanceId: instance.id,
        assignee: 'Unassigned',
        candidateRoles: step.role ? [step.role] : [],
        candidateGroups: step.groupId ? [step.groupId] : [],
        requiredSkills: step.requiredSkills || [],
        dueDate: new Date(Date.now() + 86400000 * (step.slaDays || 2)).toISOString().split('T')[0],
        status: TaskStatus.PENDING,
        priority: instance.priority,
        description: step.description,
        stepId: step.id,
        comments: [],
        attachments: []
      };
      await dbService.add('tasks', newTask);
      setTasks(prev => [newTask, ...prev]);
    } else if (step.type === 'decision' || step.type === 'parallel-gateway') {
      await advanceWorkflow(instance.id, step.id, 'auto_pass');
    }
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    if (!hasPermission(Permission.PROCESS_START)) throw new Error("Unauthorized to start processes");
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id],
      startDate: new Date().toISOString(),
      variables: inputData || {},
      priority: TaskPriority.MEDIUM,
      comments: [],
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: currentUser?.name || 'User',
        timestamp: new Date().toISOString()
      }],
      complianceVerified: definition.complianceLevel === 'Standard',
      domainId: currentUser?.domainId || 'default'
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);
    await logAudit('START', 'Instance', instanceId, `Started instance of ${definition.name}`);
    await advanceWorkflow(instanceId, startStep.id, 'started');
    return instanceId;
  };

  const claimTask = async (taskId: string) => {
    if (!currentUser) return;
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    // 1. RBAC and Group Check
    const userRoleIds = currentUser.roleIds;
    const userGroupIds = currentUser.groupIds;
    const userSkills = currentUser.skills || [];

    // 2. Skill Validation (Feature 10)
    const hasRequiredSkills = task.requiredSkills.every(s => userSkills.includes(s));
    if (task.requiredSkills.length > 0 && !hasRequiredSkills && !userRoleIds.includes('admin')) {
      throw new Error(`Insufficient skills. Required: ${task.requiredSkills.join(', ')}`);
    }

    const isCandidate = task.candidateRoles.some(r => userRoleIds.includes(r)) || 
                        task.candidateGroups.some(g => userGroupIds.includes(g)) ||
                        userRoleIds.includes('admin');

    if (!isCandidate) {
      // 3. Delegation Logic (Feature 5)
      const activeDelegations = delegations.filter(d => d.toUserId === currentUser.id && d.isActive);
      const isDelegate = activeDelegations.some(d => {
        const originalUser = users.find(u => u.id === d.fromUserId);
        return originalUser && (
          task.candidateRoles.some(r => originalUser.roleIds.includes(r)) ||
          task.candidateGroups.some(g => originalUser.groupIds.includes(g))
        );
      });
      if (!isDelegate) throw new Error("You are not a candidate or delegate for this task.");
    }

    const updatedTask = { ...task, status: TaskStatus.CLAIMED, assignee: currentUser.id };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    await logAudit('CLAIM', 'Task', taskId, `Task claimed by ${currentUser.name}`);
  };

  const releaseTask = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const updatedTask = { ...task, status: TaskStatus.PENDING, assignee: 'Unassigned' };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    await logAudit('RELEASE', 'Task', taskId, `Task released to candidate pool`);
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    if (!hasPermission(Permission.TASK_COMPLETE)) throw new Error("Unauthorized to complete tasks");
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const hist: TaskHistory = {
        id: `h-${Date.now()}`,
        stepName: task.title,
        action,
        performer: currentUser?.name || 'Principal Admin',
        timestamp: new Date().toISOString(),
        comments
      };
      const updatedInst = { ...instance, history: [...instance.history, hist] };
      await dbService.add('instances', updatedInst);
      setInstances(prev => prev.map(i => i.id === instance.id ? updatedInst : i));

      await logAudit('COMPLETE', 'Task', taskId, `Task completed with action: ${action}`);
      if (action !== 'reject') {
        await advanceWorkflow(instance.id, task.stepId, action);
      } else {
        const terminated = { ...updatedInst, status: 'Terminated' as any, activeStepIds: [] };
        await dbService.add('instances', terminated);
        setInstances(prev => prev.map(i => i.id === instance.id ? terminated : i));
        await logAudit('TERMINATE', 'Instance', instance.id, `Process terminated due to rejection at ${task.title}`);
      }
    }
  };

  const addTaskComment = async (taskId: string, text: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const newComment: Comment = {
      id: `c-${Date.now()}`,
      userId: currentUser?.id || 'system',
      userName: currentUser?.name || 'System',
      text,
      timestamp: new Date().toISOString()
    };
    const updatedTask = { ...task, comments: [...task.comments, newComment] };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
  };

  const updateUser = async (user: User) => {
    await dbService.add('users', user);
    setUsers(prev => prev.map(u => u.id === user.id ? user : u));
    if (currentUser?.id === user.id) setLocalCurrentUser(user);
    await logAudit('UPDATE', 'User', user.id, `User profile updated for ${user.name}`);
  };

  const addDelegation = async (del: Omit<Delegation, 'id'>) => {
    const newDel: Delegation = { ...del, id: `del-${Date.now()}` };
    await dbService.add('delegations', newDel);
    setDelegations(prev => [...prev, newDel]);
    await logAudit('CREATE', 'User', del.fromUserId, `Delegation added to ${del.toUserId}`);
  };

  const revokeDelegation = async (id: string) => {
    await dbService.delete('delegations', id);
    setDelegations(prev => prev.filter(d => d.id !== id));
  };

  const adminOverrideStep = async (instanceId: string, targetStepId: string) => {
    if (!hasPermission(Permission.TASK_OVERRIDE)) throw new Error("Unauthorized to override steps");
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const updatedInstance: ProcessInstance = {
      ...instance,
      activeStepIds: [targetStepId],
      history: [...instance.history, {
        id: `hist-${Date.now()}`,
        stepName: 'Admin Move',
        action: 'Override',
        performer: currentUser?.name || 'Administrator',
        timestamp: new Date().toISOString()
      }]
    };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
    await logAudit('OVERRIDE', 'Instance', instanceId, `Admin moved execution pointer to ${targetStepId}`, 'Warning');
  };

  const updateInstanceVariables = async (instanceId: string, variables: Record<string, any>) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, variables };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
      await logAudit('UPDATE', 'Instance', instanceId, `State variables modified by administrator`);
    }
  };

  const toggleInstanceSuspension = async (instanceId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, status: instance.status === 'Suspended' ? 'Active' : 'Suspended' } as any;
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
      await logAudit('SUSPEND', 'Instance', instanceId, `Instance suspension toggled`);
    }
  };

  const addInstanceComment = async (instanceId: string, text: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const newComment: Comment = {
        id: `c-${Date.now()}`,
        userId: currentUser?.id || 'system',
        userName: currentUser?.name || 'System',
        text,
        timestamp: new Date().toISOString()
      };
      const updated = { ...instance, comments: [...instance.comments, newComment] };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const resetSystem = async () => { 
    await dbService.resetDB(); 
    await logAudit('RESET', 'System', 'nexflow', 'Total system factory reset performed', 'Alert');
    await loadData(); 
  };

  const reseedSystem = async () => { 
    await dbService.reseed(); 
    await logAudit('RESEED', 'System', 'nexflow', 'System reseeded with enterprise demo data');
    await loadData(); 
  };

  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_enterprise_${Date.now()}.json`;
    a.click();
    await logAudit('EXPORT', 'System', 'nexflow', 'Enterprise data backup exported');
  };

  const importData = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      await dbService.importData(e.target?.result as string);
      await logAudit('IMPORT', 'System', 'nexflow', 'Enterprise data restored from backup', 'Warning');
      await loadData();
    };
    reader.readAsText(file);
  };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, auditLogs, users, roles, groups, delegations, currentUser, loading, error,
      nav, navigateTo, setCurrentUser: setLocalCurrentUser, hasPermission,
      viewingInstanceId, openInstanceViewer: setViewingInstanceId, closeInstanceViewer: () => setViewingInstanceId(null),
      deployProcess, startProcess, claimTask, releaseTask, completeTask, addTaskComment,
      updateUser, addDelegation, revokeDelegation,
      adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment,
      resetSystem, reseedSystem, exportData, importData, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { useState, useRef, useMemo } from 'react';
import { ProcessStep, ProcessLink, Swimlane } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Save, Play, User, Cog, GitBranch, Flag, Plus, 
  Menu, Search, Box, Ruler, Smartphone, X, Landmark, Users as UsersIcon, ChevronDown, Award
} from 'lucide-react';

const GRID_SIZE = 20;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, groups } = useBPM();
  const [processName, setProcessName] = useState('Enterprise Workflow v2');

  const [isPaletteOpen, setIsPaletteOpen] = useState(window.innerWidth > 1024);
  const [isPropertiesOpen, setIsPropertiesOpen] = useState(false);
  const [showGrid, setShowGrid] = useState(true);
  const [isMobilePreview, setIsMobilePreview] = useState(window.innerWidth < 768);

  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [lanes, setLanes] = useState<Swimlane[]>([
    { id: 'lane-1', name: 'Operational Layer', height: 250 },
    { id: 'lane-2', name: 'Management Control', height: 250 }
  ]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const addNode = (type: ProcessStep['type']) => {
    const world = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: `New ${type.replace('-', ' ')}`,
      type,
      description: '',
      position: { x: snapToGrid(world.x), y: snapToGrid(world.y) },
      nextStepIds: [],
      requiredSkills: []
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
    setIsPropertiesOpen(true);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) {
      dragTarget.current = 'link';
      activeId.current = handleEl.getAttribute('data-handle-id');
    } else if (nodeEl) {
      dragTarget.current = 'node';
      activeId.current = nodeEl.getAttribute('data-node-id');
      setSelectedId(activeId.current);
      setIsPropertiesOpen(true);
    } else {
      dragTarget.current = 'viewport';
      if (!isPropertiesOpen) setSelectedId(null);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = (e.clientX - dragStart.current.x) / viewport.zoom;
    const dy = (e.clientY - dragStart.current.y) / viewport.zoom;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { 
        ...s, 
        position: { x: (s.position?.x || 0) + dx, y: (s.position?.y || 0) + dy } 
      } : s));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'link' && activeId.current) {
      const sNode = steps.find(s => s.id === activeId.current);
      if (sNode) {
        const world = screenToWorld(e.clientX, e.clientY);
        ghostLink.current = { x1: (sNode.position?.x||0)+180, y1: (sNode.position?.y||0)+40, x2: world.x, y2: world.y };
        setViewport(v => ({...v}));
      }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      if (tId && tId !== activeId.current) {
        setLinks(prev => [...prev, { id: `link-${Date.now()}`, sourceId: activeId.current!, targetId: tId }]);
      }
    }

    if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? {
         ...s,
         position: { x: snapToGrid(s.position?.x||0), y: snapToGrid(s.position?.y||0) }
       } : s));
    }

    isDragging.current = false;
    ghostLink.current = null;
    setViewport(v => ({...v}));
  };

  const selectedStep = steps.find(s => s.id === selectedId);

  const toggleSkill = (skill: string) => {
    if (!selectedId) return;
    setSteps(prev => prev.map(s => {
      if (s.id !== selectedId) return s;
      const skills = s.requiredSkills || [];
      return {
        ...s,
        requiredSkills: skills.includes(skill) ? skills.filter(sk => sk !== skill) : [...skills, skill]
      };
    }));
  };

  return (
    <div className={`h-[calc(100vh-140px)] flex flex-col md:flex-row bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden relative shadow-2xl transition-all ${isMobilePreview ? 'max-w-[420px] mx-auto ring-8 ring-slate-800' : 'w-full'}`}>

      <div className="bg-white border-b border-slate-200 p-3 flex justify-between items-center z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsPaletteOpen(!isPaletteOpen)} className="p-2 bg-slate-50 border rounded-lg hover:bg-slate-100"><Menu size={18}/></button>
          <input className="w-48 px-3 py-1.5 bg-slate-50 border rounded-lg text-xs font-bold" value={processName} onChange={e => setProcessName(e.target.value)}/>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={() => setShowGrid(!showGrid)} className={`p-2 ${showGrid ? 'text-brand-600' : 'text-slate-400'}`}><Ruler size={18}/></button>
           <button onClick={() => setIsMobilePreview(!isMobilePreview)} className={`p-2 ${isMobilePreview ? 'text-brand-600' : 'text-slate-400'}`}><Smartphone size={18}/></button>
           <div className="h-6 w-px bg-slate-200 mx-2"></div>
           <button onClick={() => deployProcess({ name: processName, description: 'Enterprise Workflow', steps, links, lanes, deployedBy: 'Principal Admin' })} className="bg-brand-600 text-white px-4 py-1.5 rounded-lg font-bold text-xs shadow-lg hover:bg-brand-700 flex items-center gap-2">
             <Save size={16}/> Deploy
           </button>
        </div>
      </div>

      <aside className={`absolute inset-y-0 left-0 w-72 bg-white/95 backdrop-blur-md border-r border-slate-200 z-40 transition-transform duration-300 transform md:relative md:translate-x-0 ${isPaletteOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}`}>
        <div className="p-4 border-b flex justify-between items-center">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Modeler Palette</span>
          <button onClick={() => setIsPaletteOpen(false)} className="md:hidden"><X size={16}/></button>
        </div>
        <div className="p-4 space-y-6 overflow-y-auto h-full scrollbar-hide pb-20">
           <section className="space-y-2">
             <h4 className="text-[9px] font-bold text-slate-400 uppercase">Flow Components</h4>
             <div className="grid grid-cols-2 gap-2">
                <PaletteItem icon={Play} label="Start" color="text-green-500" onClick={() => addNode('start')} />
                <PaletteItem icon={Flag} label="End" color="text-slate-800" onClick={() => addNode('end')} />
                <PaletteItem icon={User} label="Human" color="text-blue-500" onClick={() => addNode('user-task')} />
                <PaletteItem icon={Cog} label="System" color="text-purple-500" onClick={() => addNode('service-task')} />
                <PaletteItem icon={GitBranch} label="XOR Gate" color="text-amber-500" onClick={() => addNode('decision')} />
                <PaletteItem icon={Box} label="Subprocess" color="text-indigo-500" onClick={() => addNode('sub-process')} />
             </div>
           </section>
        </div>
      </aside>

      <div className="flex-1 relative overflow-hidden bg-slate-50 touch-none select-none">
        <div ref={canvasRef} className="absolute inset-0 cursor-crosshair" onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}
          style={{ backgroundImage: showGrid ? 'radial-gradient(#cbd5e1 1.5px, transparent 1.5px)' : 'none', backgroundSize: `${20*viewport.zoom}px ${20*viewport.zoom}px`, backgroundPosition: `${viewport.x}px ${viewport.y}px` }}>
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
            <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
              <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#94a3b8"/></marker></defs>
              {links.map(l => {
                const s = steps.find(n => n.id === l.sourceId);
                const t = steps.find(n => n.id === l.targetId);
                if (!s || !t) return null;
                const x1=(s.position?.x||0)+180; const y1=(s.position?.y||0)+40;
                const x2=(t.position?.x||0); const y2=(t.position?.y||0)+40;
                return <path key={l.id} d={`M ${x1} ${y1} C ${x1+60} ${y1}, ${x2-60} ${y2}, ${x2} ${y2}`} stroke="#94a3b8" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>
              })}
              {ghostLink.current && <line x1={ghostLink.current.x1} y1={ghostLink.current.y1} x2={ghostLink.current.x2} y2={ghostLink.current.y2} stroke="#0ea5e9" strokeWidth="2" strokeDasharray="4,4"/>}
            </svg>

            {steps.map(step => (
              <div key={step.id} data-node-id={step.id}
                className={`absolute w-[180px] h-[80px] bg-white rounded-xl border-2 shadow-sm p-3 flex flex-col transition-all active:scale-95 ${selectedId === step.id ? 'border-brand-500 shadow-xl z-30 scale-105' : 'border-slate-200'}`}
                style={{ left: step.position?.x, top: step.position?.y }}>
                <div className="flex items-center justify-between opacity-50 mb-1">
                  <span className="text-[8px] font-black uppercase text-slate-400">{step.type}</span>
                  <div data-handle-id={step.id} className="w-5 h-5 bg-slate-100 border rounded-full flex items-center justify-center cursor-crosshair hover:bg-brand-500 hover:text-white transition-colors"><Plus size={10}/></div>
                </div>
                <div className="text-xs font-bold text-slate-800 truncate">{step.name}</div>
                <div className="mt-auto flex justify-between items-center text-[7px] font-bold text-slate-400">
                   <span className="bg-slate-50 px-1 rounded uppercase flex items-center gap-1">
                      {step.role ? <Shield size={8}/> : step.groupId ? <Landmark size={8}/> : null}
                      {step.role || step.groupId || 'Unassigned'}
                   </span>
                   {step.requiredSkills && step.requiredSkills.length > 0 && <Award size={10} className="text-brand-500"/>}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <aside className={`fixed inset-x-0 bottom-0 bg-white shadow-2xl z-[60] border-t transition-transform duration-500 md:relative md:inset-y-0 md:border-t-0 md:border-l md:w-96 md:translate-y-0 ${selectedId && isPropertiesOpen ? 'translate-y-0' : 'translate-y-full'}`}>
         <div className="p-4 border-b flex items-center justify-between bg-slate-50/50">
            <h3 className="font-black text-slate-800 text-xs uppercase tracking-widest">Enterprise Routing</h3>
            <button onClick={() => setIsPropertiesOpen(false)} className="p-2 text-slate-400 hover:bg-slate-100 rounded-lg"><ChevronDown size={18}/></button>
         </div>
         {selectedStep && (
           <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh] md:max-h-full scrollbar-hide">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Activity Label</label>
                <input className="w-full p-3 bg-slate-50 border rounded-xl text-sm font-bold focus:ring-2 focus:ring-brand-500" value={selectedStep.name} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, name: e.target.value} : s))}/>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Target Role</label>
                  <select 
                    className="w-full p-3 bg-slate-50 border rounded-xl text-sm appearance-none"
                    value={selectedStep.role || ''}
                    onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, role: e.target.value, groupId: undefined} : s))}
                  >
                    <option value="">None (Generic)</option>
                    {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Required Skills (Dynamic Routing)</label>
                  <div className="flex flex-wrap gap-2 pt-2">
                     {['BPMN', 'Leadership', 'Accounting', 'Logistics', 'Audit', 'Planning'].map(skill => (
                       <button 
                        key={skill}
                        onClick={() => toggleSkill(skill)}
                        className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${selectedStep.requiredSkills?.includes(skill) ? 'bg-brand-600 text-white border-brand-600 shadow-md' : 'bg-white text-slate-500 border-slate-200'}`}
                       >
                         {skill}
                       </button>
                     ))}
                  </div>
                </div>
              </div>

              <div className="pt-4 border-t flex gap-3">
                 <button onClick={() => { setSteps(prev => prev.filter(s => s.id !== selectedId)); setLinks(prev => prev.filter(l => l.sourceId !== selectedId && l.targetId !== selectedId)); setSelectedId(null); }} className="flex-1 py-3 bg-red-50 text-red-700 rounded-xl font-bold text-xs uppercase">Delete</button>
                 <button className="flex-1 py-3 bg-brand-600 text-white rounded-xl font-bold text-xs uppercase" onClick={() => setIsPropertiesOpen(false)}>Commit</button>
              </div>
           </div>
         )}
      </aside>
    </div>
  );
};

