  <button onClick={onClick} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 transition-all hover:shadow-md">
    <Icon size={20} className={color}/>
    <span className="text-[10px] font-bold text-slate-600">{label}</span>
  </button>
);

const Shield = ({ size }: { size: number }) => <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>;

import React, { useState } from 'react';
import { Task, TaskStatus, TaskPriority } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { Search, Filter, Check, X, AlertOctagon, Clock, ChevronRight, FileText, History, User, Map, MessageCircle, Send, Users, CheckSquare, Award } from 'lucide-react';

export const TaskInbox: React.FC = () => {
  const { tasks, completeTask, claimTask, releaseTask, addTaskComment, instances, openInstanceViewer, currentUser } = useBPM();
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [commentText, setCommentText] = useState('');

  const displayTasks = tasks.sort((a,b) => new Date(b.dueDate).getTime() - new Date(a.dueDate).getTime());

  const getPriorityColor = (p: TaskPriority) => {
    switch (p) {
      case TaskPriority.CRITICAL: return 'bg-red-100 text-red-700 border-red-200';
      case TaskPriority.HIGH: return 'bg-orange-100 text-orange-700 border-orange-200';
      case TaskPriority.MEDIUM: return 'bg-blue-100 text-blue-700 border-blue-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  const handleAction = async (id: string, action: 'approve' | 'reject') => {
    try {
      await completeTask(id, action, action === 'approve' ? 'Approved by user' : 'Rejected by user');
      setSelectedTask(null);
    } catch (e: any) {
      alert(e.message);
    }
  };

  const handleClaim = async (id: string) => {
    try {
      await claimTask(id);
    } catch (e: any) {
      alert(e.message);
    }
  };

  const handleCommentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTask || !commentText.trim()) return;
    addTaskComment(selectedTask.id, commentText);
    setCommentText('');
