export const TaskInbox: React.FC = () => {
  const { tasks, completeTask, claimTask, releaseTask, addTaskComment, instances, currentUser } = useBPM();
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [commentText, setCommentText] = useState('');

  const myTasks = tasks.filter(t => t.assignee === currentUser?.id);
  const unassignedTasks = tasks.filter(t => t.status === TaskStatus.PENDING && t.assignee === 'Unassigned');

  const getPriorityClasses = (p: TaskPriority) => {
    switch (p) {
      case TaskPriority.CRITICAL: return { bg: 'bg-red-50', text: 'text-red-700', border: 'border-red-200' };
      case TaskPriority.HIGH: return { bg: 'bg-orange-50', text: 'text-orange-700', border: 'border-orange-200' };
      case TaskPriority.MEDIUM: return { bg: 'bg-blue-50', text: 'text-blue-700', border: 'border-blue-200' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-700', border: 'border-slate-200' };
    }
  };

  const handleAction = async (id: string, action: 'approve' | 'reject') => {
    try {
      await completeTask(id, action, action === 'approve' ? 'Approved by user' : 'Rejected by user');
      setSelectedTask(null);
    } catch (e: any) {
      alert(e.message);
    }
  };

  const handleClaim = async (id: string) => {
    try {
      await claimTask(id);
      const claimedTask = tasks.find(t => t.id === id);
      if (claimedTask) {
        setSelectedTask({ ...claimedTask, status: TaskStatus.CLAIMED, assignee: currentUser?.id || '' });
      }
    } catch (e: any) {
      alert(e.message);
    }
  };

  const handleCommentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTask || !commentText.trim()) return;
    addTaskComment(selectedTask.id, commentText);
    const newComment = { id: `c-${Date.now()}`, userId: currentUser?.id || '', userName: currentUser?.name || 'User', text: commentText, timestamp: new Date().toISOString() };
    setSelectedTask(prev => prev ? { ...prev, comments: [...prev.comments, newComment] } : null);
    setCommentText('');
  };

  const TaskListItem = ({ task }: { task: Task }) => {
    const priorityClasses = getPriorityClasses(task.priority);
    return (
      <div 
        onClick={() => setSelectedTask(task)}
        className={`p-4 border-b border-slate-100 hover:bg-slate-50 cursor-pointer transition-colors relative ${selectedTask?.id === task.id ? 'bg-brand-50' : ''}`}
