          <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-wider border ${priorityClasses.bg} ${priorityClasses.text} ${priorityClasses.border}`}>{task.priority}</span>
        </div>
        <div className="flex items-center justify-between text-xs text-slate-500">
           <div className="flex items-center gap-1.5"><FileText size={12} /> <span className="truncate max-w-[120px]">{task.processName}</span></div>
           <div className="flex items-center gap-1.5"><Clock size={12} /> {task.dueDate}</div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-[calc(100vh-160px)] flex-col lg:flex-row gap-6 animate-fade-in">
      <div className={`w-full lg:w-[380px] shrink-0 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden ${selectedTask ? 'hidden lg:flex' : 'flex'}`}>
