          {myTasks.length > 0 ? myTasks.map(task => <TaskListItem key={task.id} task={task} />) : <p className="p-4 text-xs text-slate-400 italic">Your personal queue is empty.</p>}

          <div className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50/70 border-b border-t border-slate-100">Unassigned ({unassignedTasks.length})</div>
