import React, { useState } from 'react';
import { Task, TaskStatus, TaskPriority } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { Search, Filter, Check, X, AlertOctagon, Clock, ChevronRight, FileText, History, User, Map, MessageCircle, Send, Users, CheckSquare, Award } from 'lucide-react';

// FIX: Moved getPriorityClasses helper function outside the component to prevent re-creation on every render.
const getPriorityClasses = (p: TaskPriority) => {
  switch (p) {
    case TaskPriority.CRITICAL: return { bg: 'bg-red-50', text: 'text-red-700', border: 'border-red-200' };
    case TaskPriority.HIGH: return { bg: 'bg-orange-50', text: 'text-orange-700', border: 'border-orange-200' };
    case TaskPriority.MEDIUM: return { bg: 'bg-blue-50', text: 'text-blue-700', border: 'border-blue-200' };
    default: return { bg: 'bg-slate-50', text: 'text-slate-700', border: 'border-slate-200' };
  }
};

// FIX: Extracted TaskListItem into a standalone component to resolve TypeScript errors and improve performance.
interface TaskListItemProps {
  task: Task;
  selectedTask: Task | null;
  onSelectTask: (task: Task) => void;
}

const TaskListItem: React.FC<TaskListItemProps> = ({ task, selectedTask, onSelectTask }) => {
  const priorityClasses = getPriorityClasses(task.priority);
  return (
    <div 
      onClick={() => onSelectTask(task)}
      className={`p-4 border-b border-slate-100 hover:bg-slate-50 cursor-pointer transition-colors relative ${selectedTask?.id === task.id ? 'bg-brand-50' : ''}`}
    >
      {selectedTask?.id === task.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-brand-600 rounded-r-full"></div>}
      <div className="flex justify-between items-start mb-1.5">
        <h4 className="text-sm font-bold text-slate-800 pr-4 leading-tight">{task.title}</h4>
        <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-wider border ${priorityClasses.bg} ${priorityClasses.text} ${priorityClasses.border}`}>{task.priority}</span>
      </div>
      <div className="flex items-center justify-between text-xs text-slate-500">
         <div className="flex items-center gap-1.5"><FileText size={12} /> <span className="truncate max-w-[120px]">{task.processName}</span></div>
         <div className="flex items-center gap-1.5"><Clock size={12} /> {task.dueDate}</div>
      </div>
    </div>
  );
};

export const TaskInbox: React.FC = () => {
  const { tasks, completeTask, claimTask, releaseTask, addTaskComment, instances, currentUser } = useBPM();
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [commentText, setCommentText] = useState('');

  const myTasks = tasks.filter(t => t.assignee === currentUser?.id);
  const unassignedTasks = tasks.filter(t => t.status === TaskStatus.PENDING && t.assignee === 'Unassigned');

  const handleAction = async (id: string, action: 'approve' | 'reject') => {
    try {
      await completeTask(id, action, action === 'approve' ? 'Approved by user' : 'Rejected by user');
      setSelectedTask(null);
    } catch (e: any) {
      alert(e.message);
    }
  };

  const handleClaim = async (id: string) => {
    try {
      await claimTask(id);
      const claimedTask = tasks.find(t => t.id === id);
      if (claimedTask) {
        setSelectedTask({ ...claimedTask, status: TaskStatus.CLAIMED, assignee: currentUser?.id || '' });
      }
    } catch (e: any) {
      alert(e.message);
    }
  };

  const handleCommentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTask || !commentText.trim()) return;
    addTaskComment(selectedTask.id, commentText);
    const newComment = { id: `c-${Date.now()}`, userId: currentUser?.id || '', userName: currentUser?.name || 'User', text: commentText, timestamp: new Date().toISOString() };
    setSelectedTask(prev => prev ? { ...prev, comments: [...prev.comments, newComment] } : null);
    setCommentText('');
  };

  return (
    <div className="flex h-[calc(100vh-160px)] flex-col lg:flex-row gap-6 animate-fade-in">
      <div className={`w-full lg:w-[380px] shrink-0 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden ${selectedTask ? 'hidden lg:flex' : 'flex'}`}>
        <div className="p-4 border-b border-slate-100">
           <div className="relative">
             <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
             <input type="text" placeholder="Search tasks..." className="w-full pl-10 pr-4 py-2.5 bg-slate-100 border-2 border-transparent rounded-lg text-sm focus:bg-white focus:border-brand-300 focus:outline-none"/>
           </div>
        </div>
        <div className="flex-1 overflow-y-auto">
          <div className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50/70 border-b border-slate-100">My Queue ({myTasks.length})</div>
          {myTasks.length > 0 ? myTasks.map(task => <TaskListItem key={task.id} task={task} selectedTask={selectedTask} onSelectTask={setSelectedTask} />) : <p className="p-4 text-xs text-slate-400 italic">Your personal queue is empty.</p>}

          <div className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50/70 border-b border-t border-slate-100">Unassigned ({unassignedTasks.length})</div>
          {unassignedTasks.length > 0 ? unassignedTasks.map(task => <TaskListItem key={task.id} task={task} selectedTask={selectedTask} onSelectTask={setSelectedTask} />) : <p className="p-4 text-xs text-slate-400 italic">No unassigned tasks.</p>}
        </div>
      </div>

      <div className={`flex-1 bg-white rounded-2xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${selectedTask ? 'flex' : 'hidden lg:flex'}`}>
        {selectedTask ? (
          <>
            <div className="p-6 border-b border-slate-100 flex flex-col md:flex-row justify-between items-start bg-slate-50/30 gap-4">
              <div className="flex-1 w-full">
                <button onClick={() => setSelectedTask(null)} className="lg:hidden mb-4 flex items-center gap-2 text-xs font-black text-brand-600 uppercase tracking-widest">
                  <ChevronRight className="rotate-180" size={14} /> Back to Worklist
                </button>
                <div className="flex items-center gap-3 mb-2">
                  <span className={`px-2 py-1 rounded-md text-[10px] font-black uppercase border ${getPriorityClasses(selectedTask.priority).bg} ${getPriorityClasses(selectedTask.priority).text} ${getPriorityClasses(selectedTask.priority).border}`}>{selectedTask.priority}</span>
                  <span className="text-xs text-slate-400 font-bold tracking-widest uppercase">{selectedTask.id}</span>
                </div>
                <h2 className="text-2xl font-black text-slate-800 leading-tight">{selectedTask.title}</h2>
                <p className="text-sm text-slate-500 font-medium mt-1">{selectedTask.processName}</p>
              </div>
              <div className="flex w-full md:w-auto items-center gap-3 shrink-0">
                 {selectedTask.status === TaskStatus.PENDING && (
                   <button onClick={() => handleClaim(selectedTask.id)} className="w-full md:w-auto bg-brand-600 text-white px-6 py-3 rounded-xl text-sm font-bold shadow-lg shadow-brand-100 flex items-center justify-center gap-2 hover:bg-brand-700 transition-all">
                     <Users size={16}/> Claim Task
                   </button>
                 )}
                 {selectedTask.status === TaskStatus.CLAIMED && (
                   <button onClick={() => releaseTask(selectedTask.id)} className="w-full md:w-auto px-4 py-2 text-slate-500 bg-slate-100 border border-slate-200 rounded-xl text-xs font-black uppercase hover:bg-slate-200">
                     Release
