               {selectedTask.requiredSkills.length > 0 && (
                 <section className="p-4 bg-brand-50 border border-brand-100 rounded-xl">
                    <h4 className="text-[10px] font-black text-brand-700 uppercase mb-2 flex items-center gap-2"><Award size={14}/> Required Skills</h4>
                    <div className="flex flex-wrap gap-2">
