                         <div>
                            <div className="flex items-center gap-2">
                              <span className="text-xs font-bold text-slate-800">{c.userName}</span>
                              <span className="text-[10px] text-slate-400">{new Date(c.timestamp).toLocaleString()}</span>
                            </div>
                            <p className="text-sm text-slate-600 bg-slate-50 p-3 rounded-lg mt-1 border border-slate-100">{c.text}</p>
                         </div>
                      </div>
                    ))}
                    <form onSubmit={handleCommentSubmit} className="flex gap-3 pt-2">
                       <input className="flex-1 px-4 py-3 bg-white border-2 border-slate-200 rounded-lg text-sm focus:border-brand-400 focus:outline-none" placeholder="Add a comment..." value={commentText} onChange={e => setCommentText(e.target.value)} />
                       <button className="p-3 bg-slate-900 text-white rounded-lg shadow-md hover:bg-slate-800"><Send size={18}/></button>
                    </form>
                  </div>
               </section>
            </div>

            {selectedTask.assignee === currentUser?.id && (
              <div className="p-4 border-t border-slate-200 bg-slate-50 flex flex-col sm:flex-row justify-end gap-3">
                <button onClick={() => handleAction(selectedTask.id, 'reject')} className="px-6 py-3 bg-white border-2 border-slate-200 text-slate-700 rounded-xl font-bold text-sm hover:border-red-400 hover:text-red-600 transition-all">Reject</button>
                <button onClick={() => handleAction(selectedTask.id, 'approve')} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm shadow-lg shadow-slate-200 hover:bg-slate-800 transition-all active:scale-95">Complete & Commit</button>
              </div>
            )}
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 p-10 text-center">
