import React, { useState, useRef, useMemo } from 'react';
import { ProcessStep, ProcessLink, ProcessStepType } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { Save, ZoomIn, ZoomOut } from 'lucide-react';
import { PaletteSidebar } from './designer/PaletteSidebar';
import { NodeComponent } from './designer/NodeComponent';
import { PropertiesPanel } from './designer/PropertiesPanel';
import { getStepTypeMetadata } from './designer/designerUtils';

const GRID_SIZE = 20;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles } = useBPM();
  const [processName, setProcessName] = useState('New Enterprise Workflow');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 0.8 });
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;
  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return { x: (sx - rect.left - viewport.x) / viewport.zoom, y: (sy - rect.top - viewport.y) / viewport.zoom };
  };

  const addNode = (type: ProcessStepType) => {
    const world = screenToWorld(canvasRef.current!.clientWidth / 2, canvasRef.current!.clientHeight / 2);
    const metadata = getStepTypeMetadata(type);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: metadata.defaultName,
      type, description: '',
      position: { x: snapToGrid(world.x - 100), y: snapToGrid(world.y - 36) },
      requiredSkills: metadata.defaultSkills || [],
      data: {}
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');
    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;
    if (handleEl) {
      dragTarget.current = 'link'; activeId.current = handleEl.getAttribute('data-handle-id'); e.stopPropagation();
    } else if (nodeEl) {
      dragTarget.current = 'node'; activeId.current = nodeEl.getAttribute('data-node-id'); setSelectedId(activeId.current); e.stopPropagation();
    } else {
      dragTarget.current = 'viewport'; setSelectedId(null);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;
    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: (s.position?.x || 0) + dx / viewport.zoom, y: (s.position?.y || 0) + dy / viewport.zoom } } : s));
    } else if (dragTarget.current === 'link' && activeId.current) {
      const sNode = steps.find(s => s.id === activeId.current);
      if (sNode && sNode.position) {
        const world = screenToWorld(e.clientX, e.clientY);
        ghostLink.current = { x1: sNode.position.x + 200, y1: sNode.position.y + 36, x2: world.x, y2: world.y };
        setViewport(v => ({...v}));
      }
    }
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      if (tId && tId !== activeId.current) {
        setLinks(prev => [...prev, { id: `link-${Date.now()}`, sourceId: activeId.current!, targetId: tId }]);
      }
    } else if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: snapToGrid(s.position?.x || 0), y: snapToGrid(s.position?.y || 0) } } : s));
    }
    isDragging.current = false; ghostLink.current = null; activeId.current = null; setViewport(v => ({...v}));
  };

  const handleWheel = (e: React.WheelEvent) => {
    const zoomFactor = 1.1;
    const newZoom = e.deltaY > 0 ? viewport.zoom / zoomFactor : viewport.zoom * zoomFactor;
    setViewport(v => ({...v, zoom: Math.max(0.2, Math.min(2, newZoom))}));
  };

  const selectedStep = useMemo(() => steps.find(s => s.id === selectedId), [selectedId, steps]);
  const updateStep = (updatedStep: ProcessStep) => setSteps(prev => prev.map(s => s.id === updatedStep.id ? updatedStep : s));
  const deleteStep = (id: string) => {
    setSteps(prev => prev.filter(s => s.id !== id));
    setLinks(prev => prev.filter(l => l.sourceId !== id && l.targetId !== id));
    setSelectedId(null);
  };
  const handleDeploy = () => { deployProcess({ name: processName, description: 'Enterprise Workflow', steps, links, deployedBy: 'Principal Admin' }); alert('Deployment initiated.'); };

  return (
    <div className="h-[calc(100vh-144px)] flex bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden shadow-xl">
      <PaletteSidebar onAddNode={addNode} />
      <main className="flex-1 flex flex-col">
        <div className="h-16 bg-white/70 backdrop-blur-lg border-b border-slate-200 flex items-center justify-between px-4">
           <input className="font-bold text-slate-800 text-sm bg-transparent focus:bg-slate-100 rounded-md px-3 py-1 -ml-3" value={processName} onChange={e => setProcessName(e.target.value)} />
           <div className="flex items-center gap-2">
              <button onClick={() => setViewport(v => ({...v, zoom: v.zoom * 1.2}))} className="p-2 text-slate-500 hover:bg-slate-100 rounded-md"><ZoomIn size={18}/></button>
              <button onClick={() => setViewport(v => ({...v, zoom: v.zoom / 1.2}))} className="p-2 text-slate-500 hover:bg-slate-100 rounded-md"><ZoomOut size={18}/></button>
              <div className="h-6 w-px bg-slate-200 mx-2"></div>
              <button onClick={handleDeploy} className="bg-slate-900 text-white px-4 py-2 rounded-lg font-bold text-xs shadow-md hover:bg-slate-800 flex items-center gap-2"><Save size={14}/> Deploy</button>
           </div>
        </div>
        <div ref={canvasRef} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp} onWheel={handleWheel} className="flex-1 relative overflow-hidden bg-slate-50 cursor-grab active:cursor-grabbing" style={{ backgroundImage: 'radial-gradient(#e2e8f0 1px, transparent 1px)', backgroundSize: `${GRID_SIZE * viewport.zoom}px ${GRID_SIZE * viewport.zoom}px`, backgroundPosition: `${viewport.x % (GRID_SIZE * viewport.zoom)}px ${viewport.y % (GRID_SIZE * viewport.zoom)}px` }}>
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
            <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
              <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#94a3b8"/></marker></defs>
              {links.map(l => {
                const s = steps.find(n => n.id === l.sourceId); const t = steps.find(n => n.id === l.targetId);
                if (!s || !t || !s.position || !t.position) return null;
                const [x1, y1] = [s.position.x + 200, s.position.y + 36]; const [x2, y2] = [t.position.x, t.position.y + 36];
                return <path key={l.id} d={`M ${x1} ${y1} C ${x1 + 60} ${y1}, ${x2 - 60} ${y2}, ${x2} ${y2}`} stroke="#94a3b8" strokeWidth="2.5" fill="none" markerEnd="url(#arrow)"/>;
              })}
              {ghostLink.current && <path d={`M ${ghostLink.current.x1} ${ghostLink.current.y1} C ${ghostLink.current.x1 + 60} ${ghostLink.current.y1}, ${ghostLink.current.x2 - 60} ${ghostLink.current.y2}, ${ghostLink.current.x2} ${ghostLink.current.y2}`} stroke="#0ea5e9" strokeWidth="2" strokeDasharray="5,5" fill="none"/>}
            </svg>
            {steps.map(step => <NodeComponent key={step.id} step={step} isSelected={selectedId === step.id} />)}
          </div>
        </div>
      </main>
      <PropertiesPanel step={selectedStep} onUpdate={updateStep} onDelete={deleteStep} roles={roles} />
    </div>
  );
};

