import React, { useState, useCallback, ChangeEvent } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { BusinessRule, RuleCondition, RuleAction, DecisionTable } from '../types';
import { FunctionSquare, Plus, BrainCircuit, Table, TestTube, Trash2, Save, Upload, Play, ChevronRight, AlertTriangle, X } from 'lucide-react';

// --- Reusable UI Components ---
const RuleInput = ({ value, onChange, ...props }: any) => <input value={value} onChange={e => onChange(e.target.value)} className="prop-input text-xs" {...props} />;
const RuleSelect = ({ value, onChange, children }: any) => <select value={value} onChange={e => onChange(e.target.value)} className="prop-input text-xs">{children}</select>;

// --- Rule Builder Component ---
const RuleBuilder = ({ rule, onSave, onDelete }: { rule: BusinessRule, onSave: (rule: BusinessRule) => void, onDelete: (id: string) => void }) => {
    const [localRule, setLocalRule] = useState<BusinessRule>(rule);

    const updateField = (field: keyof BusinessRule, value: any) => setLocalRule(prev => ({ ...prev, [field]: value }));
    const updateCondition = (index: number, field: keyof RuleCondition, value: any) => {
        const newConditions = [...localRule.conditions];
        newConditions[index] = { ...newConditions[index], [field]: value };
        setLocalRule(prev => ({ ...prev, conditions: newConditions }));
    };
    const addCondition = () => setLocalRule(prev => ({ ...prev, conditions: [...prev.conditions, { fact: '', operator: 'eq', value: '' }] }));
    const removeCondition = (index: number) => setLocalRule(prev => ({ ...prev, conditions: prev.conditions.filter((_, i) => i !== index) }));
    const updateActionParam = (key: string, value: any) => setLocalRule(prev => ({ ...prev, action: { ...prev.action, params: { ...prev.action.params, [key]: value } } }));

    return (
        <div className="p-6 space-y-6">
            <div className="flex justify-between items-center">
                <input value={localRule.name} onChange={e => updateField('name', e.target.value)} className="text-lg font-bold text-slate-800 bg-transparent focus:bg-slate-50 rounded px-2 -ml-2 py-1 outline-none focus:ring-1 ring-brand-300" />
                <div className="flex items-center gap-2">
                    <button onClick={() => onDelete(rule.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                    <button onClick={() => onSave(localRule)} className="px-4 py-2 bg-slate-900 text-white text-xs font-bold rounded-lg flex items-center gap-2"><Save size={14} /> Save</button>
                </div>
            </div>
            <div><label className="prop-label">Description</label><RuleInput value={localRule.description} onChange={(val: string) => updateField('description', val)} /></div>

            <div className="pt-4 space-y-3">
                <h4 className="prop-section-header">IF... (All conditions are met)</h4>
                {localRule.conditions.map((cond, i) => (
                    <div key={i} className="flex items-center gap-2 p-2 bg-slate-50 border border-slate-200 rounded-lg">
                        <RuleInput placeholder="fact (e.g. invoice.amount)" value={cond.fact} onChange={(val: string) => updateCondition(i, 'fact', val)} />
                        <RuleSelect value={cond.operator} onChange={(val: string) => updateCondition(i, 'operator', val)}>
                            <option value="eq">is equal to</option><option value="neq">is not equal to</option><option value="gt">is greater than</option><option value="lt">is less than</option><option value="contains">contains</option>
                        </RuleSelect>
                        <RuleInput placeholder="value (e.g. 5000)" value={cond.value} onChange={(val: string) => updateCondition(i, 'value', val)} />
                        <button onClick={() => removeCondition(i)} className="p-2 text-slate-400 hover:text-red-500 rounded"><X size={14} /></button>
                    </div>
                ))}
                <button onClick={addCondition} className="text-xs font-bold text-brand-600 hover:bg-brand-50 rounded px-2 py-1 flex items-center gap-1"><Plus size={14} /> Add Condition</button>
            </div>

            <div className="pt-4 space-y-3">
                <h4 className="prop-section-header">THEN...</h4>
                <div className="p-3 bg-slate-50 border border-slate-200 rounded-lg space-y-2">
                    <RuleSelect value={localRule.action.type} onChange={(val: string) => updateField('action', { ...localRule.action, type: val as RuleAction['type'] })}>
                        <option value="SET_VARIABLE">Set Process Variable</option><option value="ROUTE_TO">Route to User/Group</option><option value="SEND_NOTIFICATION">Send Notification</option>
                    </RuleSelect>
                    {localRule.action.type === 'SET_VARIABLE' && <>
                        <RuleInput placeholder="Variable Name" value={localRule.action.params.variableName || ''} onChange={(val: string) => updateActionParam('variableName', val)} />
                        <RuleInput placeholder="New Value" value={localRule.action.params.value || ''} onChange={(val: string) => updateActionParam('value', val)} />
                    </>}
                </div>
            </div>
        </div>
    );
};

// --- Decision Table Editor ---
const DecisionTableEditor = ({ table, onSave, onDelete }: { table: DecisionTable, onSave: (table: DecisionTable) => void, onDelete: (id: string) => void }) => {
    const [localTable, setLocalTable] = useState<DecisionTable>(table);
    const fileInputRef = React.useRef<HTMLInputElement>(null);

    const handleFileUpload = (e: ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (event) => {
            const text = event.target?.result as string;
            const rows = text.split('\n').map(row => row.trim().split(','));
            const header = rows.shift() || [];
            // Simple assumption: last column is the output
            const inputs = header.slice(0, -1);
            const outputs = header.slice(-1);
            setLocalTable(prev => ({ ...prev, inputs, outputs, rules: rows.map(r => r.map(v => isNaN(Number(v)) ? v : Number(v))) }));
        };
        reader.readAsText(file);
    };

    return (
        <div className="p-6 space-y-6">
            <div className="flex justify-between items-center">
                <input value={localTable.name} onChange={e => setLocalTable(prev => ({...prev, name: e.target.value}))} className="text-lg font-bold text-slate-800 bg-transparent focus:bg-slate-50 rounded px-2 -ml-2 py-1 outline-none focus:ring-1 ring-brand-300" />
                <div className="flex items-center gap-2">
                    <button onClick={() => onDelete(table.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                    <button onClick={() => onSave(localTable)} className="px-4 py-2 bg-slate-900 text-white text-xs font-bold rounded-lg flex items-center gap-2"><Save size={14} /> Save</button>
                </div>
            </div>

            <button onClick={() => fileInputRef.current?.click()} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-xl text-center hover:border-brand-400 hover:bg-brand-50 transition-colors">
                <Upload size={24} className="mx-auto text-slate-400 mb-2" />
                <h4 className="text-sm font-bold text-slate-700">Upload Decision Logic</h4>
                <p className="text-xs text-slate-500">Select a CSV file. The last column will be treated as the output.</p>
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".csv" className="hidden" />
            </button>

            {localTable.rules.length > 0 && (
                <div className="overflow-x-auto border border-slate-200 rounded-xl">
                    <table className="w-full text-xs text-left">
                        <thead className="bg-slate-100">
                            <tr>
                                {[...localTable.inputs, ...localTable.outputs].map((h, i) => (
                                    <th key={i} className={`px-4 py-2 font-bold ${i >= localTable.inputs.length ? 'bg-brand-50 text-brand-700' : ''}`}>{h}</th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {localTable.rules.map((row, i) => <tr key={i}>{row.map((cell, j) => <td key={j} className={`px-4 py-2 ${j >= localTable.inputs.length ? 'bg-slate-50 font-semibold' : ''}`}>{cell}</td>)}</tr>)}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}

// --- Rule Simulator ---
const RuleSimulator = ({ rules, decisionTables }: { rules: BusinessRule[], decisionTables: DecisionTable[] }) => {
    const { executeRules } = useBPM();
    const [selectedRuleId, setSelectedRuleId] = useState('');
    const [inputData, setInputData] = useState('{\n  "invoice": {\n    "amount": 7500,\n    "region": "EMEA"\n  }\n}');
    const [output, setOutput] = useState<any>(null);

    const handleSimulate = async () => {
        try {
            const data = JSON.parse(inputData);
            const result = await executeRules(selectedRuleId, data);
            setOutput(result);
        } catch(e) {
            setOutput({ error: (e as Error).message });
        }
    };

    return (
        <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
            <div className="space-y-4 flex flex-col">
                <h3 className="prop-section-header">Configuration</h3>
                <RuleSelect value={selectedRuleId} onChange={setSelectedRuleId}>
                    <option value="">Select a Rule or Table...</option>
                    <optgroup label="Rule Sets">
                        {rules.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </optgroup>
                     <optgroup label="Decision Tables">
                        {decisionTables.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </optgroup>
                </RuleSelect>
                <div className="flex-1 flex flex-col">
                    <label className="prop-label">Sample Input Data (JSON)</label>
                    <textarea value={inputData} onChange={e => setInputData(e.target.value)} className="prop-input flex-1 font-mono text-xs !bg-slate-900 text-green-400" />
                </div>
                <button onClick={handleSimulate} disabled={!selectedRuleId} className="w-full py-3 bg-brand-600 text-white font-bold text-sm rounded-lg flex items-center justify-center gap-2 disabled:bg-slate-300">
                    <Play size={16} /> Run Simulation
                </button>
            </div>
             <div className="space-y-4 flex flex-col">
                <h3 className="prop-section-header">Result</h3>
                <div className="flex-1 bg-slate-50 border border-slate-200 rounded-lg p-4 font-mono text-xs overflow-auto">
                    {output ? <pre>{JSON.stringify(output, null, 2)}</pre> : <span className="text-slate-400">Output will appear here...</span>}
                </div>
            </div>
        </div>
    );
};


