const BPMContext = createContext<BPMContextType | undefined>(undefined);

// Helper for dot notation access
const getFactValue = (data: any, fact: string) => {
    return fact.split('.').reduce((o, i) => (o ? o[i] : undefined), data);
};

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [roles, setRoles] = useState<UserRole[]>([]);
  const [groups, setGroups] = useState<UserGroup[]>([]);
  const [delegations, setDelegations] = useState<Delegation[]>([]);
  const [rules, setRules] = useState<BusinessRule[]>([]);
  const [decisionTables, setDecisionTables] = useState<DecisionTable[]>([]);
  const [currentUser, setLocalCurrentUser] = useState<User | null>(null);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [nav, setNav] = useState<NavigationState>({ view: 'dashboard' });
  const [viewingInstanceId, setViewingInstanceId] = useState<string | null>(null);

  const stateRef = useRef({ processes, instances, tasks, auditLogs, users, roles, groups, currentUser, delegations, rules, decisionTables });

  useEffect(() => {
    stateRef.current = { processes, instances, tasks, auditLogs, users, roles, groups, currentUser, delegations, rules, decisionTables };
  }, [processes, instances, tasks, auditLogs, users, roles, groups, currentUser, delegations, rules, decisionTables]);

  const logAudit = async (action: string, entityType: AuditLog['entityType'], entityId: string, details: string, severity: AuditLog['severity'] = 'Info') => {
    const log: AuditLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      timestamp: new Date().toISOString(),
      userId: currentUser?.name || 'system',
      action,
      entityType,
      entityId,
      details,
      severity
    };
    await dbService.add('auditLogs', log);
    setAuditLogs(prev => [log, ...prev]);
  };

  const hasPermission = (perm: Permission): boolean => {
    if (!currentUser) return false;
    const userRoles = roles.filter(r => currentUser.roleIds.includes(r.id));
    return userRoles.some(r => r.permissions.includes(perm));
  };

  const navigateTo = (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => {
    setNav({ view, selectedId: id, filter, mode });
  };

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [p, i, t, al, u, r, g, d, br, dt] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks'),
        dbService.getAll<AuditLog>('auditLogs'),
        dbService.getAll<User>('users'),
        dbService.getAll<UserRole>('roles'),
        dbService.getAll<UserGroup>('groups'),
        dbService.getAll<Delegation>('delegations'),
        dbService.getAll<BusinessRule>('rules'),
        dbService.getAll<DecisionTable>('decisionTables')
      ]);
      setProcesses(p);
      setInstances(i);
      setTasks(t);
      setAuditLogs(al || []);
      setUsers(u);
      setRoles(r);
      setGroups(g);
      setDelegations(d || []);
      setRules(br || []);
      setDecisionTables(dt || []);

      if (u.length > 0 && !stateRef.current.currentUser) {
        setLocalCurrentUser(u.find(user => user.roleIds.includes('admin')) || u[0]);
      }
    } catch (e: any) {
      setError(e.message || "DB Error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // ... (existing functions like deployProcess, etc.)
  const executeRules = async (ruleId: string, data: any): Promise<any> => {
    const { rules, decisionTables } = stateRef.current;
    const rule = rules.find(r => r.id === ruleId);
    const table = decisionTables.find(t => t.id === ruleId);

    if (rule) {
        const isTriggered = rule.conditions.every(cond => {
            const factValue = getFactValue(data, cond.fact);
            switch (cond.operator) {
                case 'eq': return factValue == cond.value;
                case 'neq': return factValue != cond.value;
                case 'gt': return factValue > cond.value;
                case 'lt': return factValue < cond.value;
                case 'contains': return String(factValue).includes(cond.value);
                default: return false;
            }
        });
        return isTriggered ? rule.action : { type: 'NO_ACTION', params: { reason: 'Conditions not met' } };
    }

    if (table) {
        const matchingRule = table.rules.find(row => {
            return table.inputs.every((inputFact, i) => getFactValue(data, inputFact) == row[i]);
        });

        if (matchingRule) {
            const result: Record<string, any> = {};
            table.outputs.forEach((outputName, i) => {
                result[outputName] = matchingRule[table.inputs.length + i];
            });
            return { type: 'SET_VARIABLE', params: result };
        }
        return { type: 'NO_ACTION', params: { reason: 'No matching row in decision table' } };
    }

    throw new Error('Rule or Table not found');
};


  const advanceWorkflow = async (instanceId: string, completedStepId: string, action: string) => {
    const { processes, instances } = stateRef.current;
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const definition = processes.find(p => p.id === instance.definitionId);
    if (!definition) return;

    const outgoingLinks = definition.links?.filter(l => l.sourceId === completedStepId) || [];
    let nextStepIds: string[] = [];

    if (outgoingLinks.length > 0) {
      nextStepIds = outgoingLinks.map(l => l.targetId);
    } else {
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);
    let updatedInstance = { ...instance, activeStepIds: newActiveStepIds };

    if (nextStepIds.length === 0 || nextStepIds.some(id => definition.steps.find(s => s.id === id)?.type === 'end')) {
      updatedInstance.status = 'Completed';
      updatedInstance.endDate = new Date().toISOString();
      updatedInstance.activeStepIds = [];
      await logAudit('FINISH', 'Instance', instance.id, `Process instance completed: ${definition.name}`);
    }

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));

    for (const stepId of nextStepIds) {
      const step = definition.steps.find(s => s.id === stepId);
      if (step) await executeStepLogic(updatedInstance, definition, step);
    }
  };

  const executeStepLogic = async (instance: ProcessInstance, definition: ProcessDefinition, step: ProcessStep) => {
    if (step.type === 'service-task') {
      setTimeout(async () => {
        const hist: TaskHistory = { id: `h-${Date.now()}`, stepName: step.name, action: 'Auto-Complete', performer: 'System Integration', timestamp: new Date().toISOString() };
        const fresh = await dbService.getAll<ProcessInstance>('instances');
        const inst = fresh.find(i => i.id === instance.id)!;
        const updated = { ...inst, history: [...inst.history, hist] };
        await dbService.add('instances', updated);
        await advanceWorkflow(instance.id, step.id, 'system_complete');
      }, 1000);
    } else if (step.type === 'user-task') {
      const newTask: Task = {
        id: `T-${Date.now()}`, title: step.name, processName: definition.name, processInstanceId: instance.id, assignee: 'Unassigned',
        candidateRoles: step.role ? [step.role] : [], candidateGroups: step.groupId ? [step.groupId] : [], requiredSkills: step.requiredSkills || [],
        dueDate: new Date(Date.now() + 86400000 * (step.slaDays || 2)).toISOString().split('T')[0], status: TaskStatus.PENDING,
        priority: instance.priority, description: step.description, stepId: step.id, comments: [], attachments: [], isAdHoc: false
      };
      await dbService.add('tasks', newTask);
      setTasks(prev => [newTask, ...prev]);
    } else if (step.type === 'rules-engine-task') {
        const ruleId = step.data?.ruleId;
        if (ruleId) {
            const resultAction = await executeRules(ruleId, instance.variables);
            if (resultAction.type === 'SET_VARIABLE') {
                const updatedInstance = { ...instance, variables: { ...instance.variables, ...resultAction.params } };
                await dbService.add('instances', updatedInstance);
                setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
                logAudit('EXECUTE', 'Rule', ruleId, `Rule set variables: ${JSON.stringify(resultAction.params)}`);
            }
        }
        await advanceWorkflow(instance.id, step.id, 'rule_complete');
    } else if (step.type === 'decision' || step.type === 'parallel-gateway') {
      await advanceWorkflow(instance.id, step.id, 'auto_pass');
    }
  };

    // Placeholder for functions that are not fully implemented yet
    const placeholder = async () => { console.warn("Functionality not implemented"); };

    // Existing functions that are complete
    const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt' | 'version' | 'isActive' | 'domainId'>) => {
        if (!hasPermission(Permission.PROCESS_DEPLOY)) throw new Error("Unauthorized to deploy processes");
        const existing = processes.find(p => p.name === processData.name);
        const newVersion = existing ? existing.version + 1 : 1;
        const newProcess: ProcessDefinition = {
            ...processData, id: `proc-${Date.now()}`, createdAt: new Date().toISOString(), version: newVersion, isActive: true,
            complianceLevel: processData.complianceLevel || 'Standard', domainId: currentUser?.domainId || 'default'
        };
        await dbService.add('processes', newProcess);
        await logAudit('DEPLOY', 'Process', newProcess.id, `Deployed version ${newVersion} of ${newProcess.name}`);
        setProcesses(prev => [newProcess, ...prev.map(p => p.name === processData.name ? { ...p, isActive: false } : p)]);
        navigateTo('processes');
    };

    const startProcess = async (definitionId: string, inputData: any) => {
        if (!hasPermission(Permission.PROCESS_START)) throw new Error("Unauthorized to start processes");
        const definition = processes.find(p => p.id === definitionId);
        if (!definition) throw new Error('Definition not found');
        const instanceId = `inst-${Date.now()}`;
        const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];
        const newInstance: ProcessInstance = {
            id: instanceId, definitionId, definitionName: definition.name, status: 'Active', activeStepIds: [startStep.id],
            startDate: new Date().toISOString(), variables: inputData || {}, priority: TaskPriority.MEDIUM, comments: [],
            history: [{ id: `hist-${Date.now()}`, stepName: 'Start', action: 'Started', performer: currentUser?.name || 'User', timestamp: new Date().toISOString() }],
            complianceVerified: definition.complianceLevel === 'Standard', domainId: currentUser?.domainId || 'default'
        };
        await dbService.add('instances', newInstance);
        setInstances(prev => [newInstance, ...prev]);
        await logAudit('START', 'Instance', instanceId, `Started instance of ${definition.name}`);
        await advanceWorkflow(instanceId, startStep.id, 'started');
        return instanceId;
    };

    const claimTask = async (taskId: string) => {
        if (!currentUser) return;
        const task = tasks.find(t => t.id === taskId);
        if (!task) return;
        const updatedTask = { ...task, status: TaskStatus.CLAIMED, assignee: currentUser.id };
        await dbService.add('tasks', updatedTask);
        setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    };

    const releaseTask = async (taskId: string) => {
        const task = tasks.find(t => t.id === taskId);
        if (!task) return;
        const updatedTask = { ...task, status: TaskStatus.PENDING, assignee: 'Unassigned' };
        await dbService.add('tasks', updatedTask);
        setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    };

    const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
        const task = tasks.find(t => t.id === taskId);
        if (!task) return;
        const updatedTask = { ...task, status: TaskStatus.COMPLETED };
        await dbService.add('tasks', updatedTask);
        setTasks(prev => prev.filter(t => t.id !== taskId));

        const instance = instances.find(i => i.id === task.processInstanceId);
        if (instance) {
          const hist: TaskHistory = { id: `h-${Date.now()}`, stepName: task.title, action, performer: currentUser?.name || 'User', timestamp: new Date().toISOString(), comments };
          const updatedInst = { ...instance, history: [...instance.history, hist] };
          await dbService.add('instances', updatedInst);
          setInstances(prev => prev.map(i => i.id === instance.id ? updatedInst : i));
          if (action !== 'reject') {
            await advanceWorkflow(instance.id, task.stepId, action);
          }
        }
    };

    const addTaskComment = async (taskId: string, text: string) => {
        const task = tasks.find(t => t.id === taskId);
        if (!task) return;
        const newComment: Comment = { id: `c-${Date.now()}`, userId: currentUser?.id || '', userName: currentUser?.name || '', text, timestamp: new Date().toISOString() };
        const updatedTask = { ...task, comments: [...task.comments, newComment] };
        await dbService.add('tasks', updatedTask);
        setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    };

    const saveRule = async (rule: BusinessRule) => {
        await dbService.add('rules', rule);
        setRules(prev => {
            const exists = prev.some(r => r.id === rule.id);
            return exists ? prev.map(r => r.id === rule.id ? rule : r) : [...prev, rule];
        });
    };
    const deleteRule = async (id: string) => {
        await dbService.delete('rules', id);
        setRules(prev => prev.filter(r => r.id !== id));
    };
    const saveDecisionTable = async (table: DecisionTable) => {
        await dbService.add('decisionTables', table);
        setDecisionTables(prev => {
            const exists = prev.some(t => t.id === table.id);
            return exists ? prev.map(t => t.id === table.id ? table : t) : [...prev, table];
        });
    };
    const deleteDecisionTable = async (id: string) => {
        await dbService.delete('decisionTables', id);
        setDecisionTables(prev => prev.filter(t => t.id !== id));
    };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, auditLogs, users, roles, groups, delegations, currentUser, loading, error, rules, decisionTables,
      nav, navigateTo, setCurrentUser: setLocalCurrentUser, hasPermission,
      viewingInstanceId, openInstanceViewer: setViewingInstanceId, closeInstanceViewer: () => setViewingInstanceId(null),
      deployProcess, startProcess, claimTask, releaseTask, completeTask, addTaskComment,
      updateUser: placeholder, addDelegation: placeholder, revokeDelegation: placeholder,
      adminOverrideStep: placeholder, updateInstanceVariables: placeholder, toggleInstanceSuspension: placeholder, addInstanceComment: placeholder,
      saveRule, deleteRule, saveDecisionTable, deleteDecisionTable, executeRules,
      resetSystem: placeholder, reseedSystem: placeholder, exportData: placeholder, importData: placeholder, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

