export const PropertiesPanel = ({ step, onUpdate, onDelete, roles }: { step: ProcessStep | undefined; onUpdate: (step: ProcessStep) => void; onDelete: (id: string) => void; roles: any[]; }) => {
    const { rules, decisionTables } = useBPM();
    if (!step) {
      return (
        <aside className="w-96 bg-white border-l border-slate-200 flex flex-col items-center justify-center text-center p-8">
          <MousePointer size={32} className="text-slate-300 mb-4" />
          <h3 className="font-bold text-slate-700">Properties</h3>
          <p className="text-xs text-slate-400 mt-1">Select a node on the canvas to view and edit its properties.</p>
        </aside>
      );
    }

    const updateField = (field: keyof ProcessStep, value: any) => { onUpdate({ ...step, [field]: value }); };
    const updateDataField = (field: string, value: any) => { onUpdate({ ...step, data: { ...step.data, [field]: value } }); };
    const toggleSkill = (skill: string) => {
        const skills = step.requiredSkills || [];
        const newSkills = skills.includes(skill) ? skills.filter(sk => sk !== skill) : [...skills, skill];
        onUpdate({ ...step, requiredSkills: newSkills });
    };

    return (
      <aside className="w-96 bg-white border-l border-slate-200 flex flex-col">
        <div className="p-4 border-b h-16 flex items-center">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Properties</h3>
        </div>
        <div className="flex-1 p-6 space-y-6 overflow-y-auto no-scrollbar">
          <div><label className="prop-label">Node Label</label><input type="text" className="prop-input" value={step.name} onChange={e => updateField('name', e.target.value)} /></div>
          <div><label className="prop-label">Description</label><textarea className="prop-input h-24" value={step.description} onChange={e => updateField('description', e.target.value)} /></div>

          {step.type === 'rules-engine-task' && (
              <div className="pt-4 border-t border-slate-100">
                <h4 className="prop-section-header">Rule Configuration</h4>
                <div>
                  <label className="prop-label">Rule/Decision Table to Execute</label>
                  <select className="prop-input" value={step.data?.ruleId || ''} onChange={e => updateDataField('ruleId', e.target.value)}>
                    <option value="">Select an asset...</option>
                    <optgroup label="Rule Sets">
                        {rules.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </optgroup>
                    <optgroup label="Decision Tables">
                        {decisionTables.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </optgroup>
                  </select>
                </div>
              </div>
          )}

          <div className="pt-4 border-t border-slate-100">
             <h4 className="prop-section-header">Routing Logic</h4>
             <div className="space-y-4">
               <div>
                  <label className="prop-label">Target Role</label>
                  <select className="prop-input" value={step.role || ''} onChange={e => updateField('role', e.target.value)}><option value="">None</option>{roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}</select>
                </div>
                <div>
                  <label className="prop-label">Required Skills</label>
                  <div className="flex flex-wrap gap-2 pt-1">
                     {['BPMN', 'Leadership', 'Accounting', 'Logistics', 'Audit', 'Planning'].map(skill => (
                       <button key={skill} onClick={() => toggleSkill(skill)} className={`px-2.5 py-1 rounded-md text-[10px] font-bold border transition-all ${step.requiredSkills?.includes(skill) ? 'bg-brand-600 text-white border-brand-600' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'}`}>{skill}</button>
                     ))}
                  </div>
                </div>
             </div>
          </div>
        </div>
        <div className="p-4 border-t border-slate-100"><button onClick={() => onDelete(step.id)} className="w-full flex items-center justify-center gap-2 py-2.5 bg-red-50 text-red-700 rounded-lg text-sm font-bold hover:bg-red-100 transition-colors"><Trash2 size={16}/> Delete Node</button></div>
      </aside>
    );
};

